var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"서윤 양, 무사했군요.","JPN":"シズカさん、ご無事でしたか。","ENG":"I'm glad you're unharmed, Seo Yoon.","TWN":"徐芸，你沒事就好。"},"stage":{"bg":"CASTLE_01","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_LAUGH"}}}},{"id":"L4_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"갑자기 통신이 두절돼서 걱정했어요. 다행입니다.","JPN":"急に通信が途絶えて心配していました。よかったです。","ENG":"We were worried when we lost contact. Thank goodness you're okay.","TWN":"突然中斷通訊，我還擔心你發生什麼事呢。幸好沒事。"},"stage":{"bg":"CASTLE_01","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_LAUGH"}}}},{"id":"L5_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"다행…… 이라고 하고 싶은데 그럴 수가 없네.","JPN":"よかった……って言いたいけどまだ言えないかな。","ENG":"I wish I could say I'm \\"okay\\"… but this doesn't look good.","TWN":"我也想說幸好……但情況似乎不太好。"},"stage":{"bg":"CASTLE_01","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"오면서 상황은 봤지?","JPN":"ここまで来る途中、状況は見たでしょ？","ENG":"You saw everything on your way here, right?","TWN":"你們來的時候有看到吧？"},"stage":{"bg":"CASTLE_01","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"네. 이 일대의 공간 구조가 미로처럼 조작됐더군요.","JPN":"はい、この一帯の空間構造が迷路のように操作されていました。","ENG":"Yes. The spatial structure around this area has been manipulated into some sort of maze.","TWN":"嗯，這一帶的空間結構似乎被人為操作成像是迷宮一樣。"},"stage":{"bg":"CASTLE_01","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"서윤 양과 마찬가지로, 함선과의 통신도 두절되었어요.","JPN":"シズカさんと同じく、艦船との通信も途絶えた状態です。","ENG":"We also lost contact with the ship, just like we did with you.","TWN":"我們也跟你一樣，無法和艦船通訊。"},"stage":{"bg":"CASTLE_01","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"맞아. 여긴 미카 말대로 방주라고 부르는 거대한 차원함선이었던 것 같아.","JPN":"ええ。ここはミカの言うとおり、箱舟と呼ばれる巨大な次元艦船だったみたい。","ENG":"Right. As Mika said, I think this used to be a giant dimensional ship, the sort they call an \\"Ark.\\"","TWN":"沒錯，這裡就像米卡說的那樣，原本是稱作方舟的次元艦船。"},"stage":{"bg":"CASTLE_01","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"그것도 공간을 조작할 수 있는 강력한 기능까지 탑재된.","JPN":"それも空間を操作できる強力な機能まで搭載されてる。","ENG":"In fact, it might be fitted with a powerful device to manipulate space itself.","TWN":"甚至還內建可以操作空間的強大功能。"},"stage":{"bg":"CASTLE_01","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"방주라…….","JPN":"箱舟ですか……","ENG":"An Ark, you say…","TWN":"方舟……"},"stage":{"bg":"CASTLE_01","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"처음 듣는 함급이군요. 공간 조작이 가능한 함선에 대한 이야기는 더더욱.","JPN":"初めて聞く艦級ですね。空間操作が可能な艦船についても同じです。","ENG":"I've never heard of such a class of ship. Especially a ship that can manipulate space.","TWN":"我還是第一次聽到呢，竟然有可以操控時間的艦船的。"},"stage":{"bg":"CASTLE_01","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"하지만 경험한 사실을 부정하는 건 제 교육관에 포함되지 않습니다.","JPN":"しかし、経験した事実を否定することは私の教育観に反することです。","ENG":"However, denying empirical evidence would be contrary to my learning philosophy.","TWN":"但我沒聽過不代表不存在，"},"stage":{"bg":"CASTLE_01","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"이제부터 어떻게 할 생각인가요?","JPN":"これからどうするつもりですか？","ENG":"So what now?","TWN":"接下來該怎麼做呢？"},"stage":{"bg":"CASTLE_01","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"안으로 들어간 미나가 밖으로 나올 수 있으려면 이 함선의 기능을 정지시켜야 해.","JPN":"中に向かったミナが外に出るためには、この艦船の機能を停止させないと。","ENG":"In order for Mina to get back out here, we'll need to stop this ship from running.","TWN":"若是要讓裡面的米娜可以出來，就必須停止這艘艦船的功能。"},"stage":{"bg":"CASTLE_01","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_SERIOUS"}}}},{"id":"L16_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"예를 들어 엔진을 부숴 버린다거나…….","JPN":"例えばエンジンを壊す、とかね。","ENG":"For instance, destroy the engine…","TWN":"像是破壞它的引擎之類的……"},"stage":{"bg":"CASTLE_01","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"……그렇군요.","JPN":"……そうですね。","ENG":"I see...","TWN":"……原來如此。"},"stage":{"bg":"CASTLE_01","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"미카, 그리고 나이엘 학생. 두 사람은 함선의 동력부를 찾아 파괴해 주세요.","JPN":"ミカさん、ナイエルさん。二人は艦船の動力部を探して破壊してください。","ENG":"Mika and Naielle. Please find and destroy the ship's power source.","TWN":"米卡和奈爾同學，請你們找出艦船的發動機並且破壞它。"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"네? 제가요?","JPN":"え？　私ですか？","ENG":"What? Me?","TWN":"嗯？你說我？"},"stage":{"bg":"CASTLE_01","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"}}}}]`);export{e as default};